const Header: React.FC<HeaderProps> = ({ page, onBack, cartItemCount, onCartClick, onSupportClick, accountSubPageTitle, orderId, checkoutPageTitle, categoryTitle, orderStatusTitle, headerConfig, searchQuery = '', setSearchQuery, isProductSaved, onSaveToggle }) => {
  const [isSearching, setIsSearching] = useState(false);

  const getHeaderInfo = () => {
    if (headerConfig) {
        return { title: headerConfig.title, subtitle: 'إدارة القسم الحالي', showBack: headerConfig.showBack };
    }

    switch(page) {
      case 'products':
        return { title: categoryTitle || 'الرئيسية', subtitle: 'اكتشف أحدث المنتجات', showBack: !!categoryTitle };
      case 'orders':
        return { title: 'الطلبات', subtitle: 'تتبع جميع طلباتك', showBack: !!orderStatusTitle };
      case 'categories':
        return { title: 'الأقسام', subtitle: 'تصفح حسب الفئة', showBack: true };
      case 'account':
        return { title: 'حسابي', subtitle: 'إدارة ملفك الشخصي', showBack: false };
      case 'financial':
        return { title: 'الحسابات', subtitle: 'إدارة أرباحك وسحوباتك', showBack: false };
      case 'productDetails':
        return { title: 'التفاصيل', subtitle: 'معلومات المنتج الكاملة', showBack: true };
      case 'cart':
        return { title: 'السلة', subtitle: 'مراجعة المنتجات المختارة', showBack: true };
      case 'checkout':
        return { title: checkoutPageTitle || 'الدفع', subtitle: 'إكمال عملية الطلب', showBack: true };
      case 'orderDetails':
        return { title: 'تفاصيل الطلب', subtitle: `#${orderId || ''}`, showBack: true };
      case 'accountSubPage':
        return { title: accountSubPageTitle || 'الإعدادات', subtitle: 'تعديل التفضيلات', showBack: true };
      default:
        return { title: 'مبيعاتنا', subtitle: 'تسوق بذكاء', showBack: false };
    }
  }

  const { title, subtitle, showBack } = getHeaderInfo();

  return (
    <header 
        className="bg-white dark:bg-slate-900 z-40 flex-shrink-0 border-b border-gray-50 dark:border-gray-800/50" 
        style={{ paddingTop: 'env(safe-area-inset-top)' }}
    >
      <div className="container mx-auto px-5 h-20 flex items-center justify-between">

        {isSearching ? (
            <div className="flex items-center w-full gap-3 animate-fade-in">
                <button 
                    onClick={() => {
                        setIsSearching(false);
                        if(setSearchQuery) setSearchQuery('');
                    }}
                    className="p-2 text-gray-400 hover:text-red-500 transition-colors"
                >
                    <XMarkIcon className="w-6 h-6" />
                </button>
                <input 
                    autoFocus
                    type="text"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery && setSearchQuery(e.target.value)}
                    placeholder="ابحث عن منتج..."
                    className="flex-grow bg-gray-50 dark:bg-gray-800 border-none rounded-xl px-4 py-2 text-sm text-right focus:ring-1 focus:ring-primary outline-none dark:text-white"
                />
            </div>
        ) : (
            <>
                {/* Right Side (Start in RTL): Title and Subtitle or Back Button */}
                <div className="flex items-center gap-3">
                    {showBack && (
                        <HeaderActionBtn onClick={onBack}>
                            <ChevronLeftIcon className="w-5 h-5" />
                        </HeaderActionBtn>
                    )}
                    <div className="flex flex-col items-start text-right">
                        <h1 className="text-[18px] font-black text-gray-900 dark:text-white leading-tight">
                            {title}
                        </h1>
                        <p className="text-[10px] font-bold text-gray-400 dark:text-gray-500">
                            {subtitle}
                        </p>
                    </div>
                </div>

                {/* Left Side (End in RTL): Action Buttons */}
                <div className="flex items-center gap-2">
                    {page === 'productDetails' ? (
                        <>
                            {onSaveToggle && (
                                <HeaderActionBtn onClick={onSaveToggle} active={isProductSaved}>
                                    <BookmarkIcon filled={isProductSaved} className="w-5 h-5" />
                                </HeaderActionBtn>
                            )}
                            <HeaderActionBtn onClick={onCartClick} badge={cartItemCount}>
                                <CartIcon className="w-5 h-5" />
                            </HeaderActionBtn>
                        </>
                    ) : showBack ? (
                        /* If it's a page with back but not product details, we might still want the cart */
                        ['cart', 'checkout', 'orderDetails', 'accountSubPage'].includes(page) ? null : (
                            <HeaderActionBtn onClick={onCartClick} badge={cartItemCount}>
                                <CartIcon className="w-5 h-5" />
                            </HeaderActionBtn>
                        )
                    ) : (
                        <>
                            <HeaderActionBtn onClick={() => setIsSearching(true)}>
                                <SearchIcon className="w-5 h-5" />
                            </HeaderActionBtn>

                            <HeaderActionBtn onClick={onCartClick} badge={cartItemCount}>
                                <CartIcon className="w-5 h-5" />
                            </HeaderActionBtn>

                            <HeaderActionBtn onClick={onSupportClick}>
                                <SupportIcon className="w-5 h-5" />
                            </HeaderActionBtn>
                        </>
                    )}
                </div>
            </>
        )}

      </div>
    </header>
  );
};

export default Header;

import React, { useState, useMemo } from 'react';
import { Product } from '../../types';
import { BookmarkIcon, PlusIcon, MinusIcon, ChevronDownIcon, XMarkIcon, CopyIcon, CartIcon, CubesStackIcon } from '../common/icons';

const ImageGalleryModal: React.FC<{
  images: string[];
  initialIndex: number;
  onClose: () => void;
  productName: string;
}> = ({ images, initialIndex, onClose, productName }) => {
    const [currentIndex, setCurrentIndex] = useState(initialIndex);
    const [touchStart, setTouchStart] = useState<number | null>(null);

    const goToPrevious = () => {
        const isFirstSlide = currentIndex === 0;
        const newIndex = isFirstSlide ? images.length - 1 : currentIndex - 1;
        setCurrentIndex(newIndex);
    };

    const goToNext = () => {
        const isLastSlide = currentIndex === images.length - 1;
        const newIndex = isLastSlide ? 0 : currentIndex + 1;
        setCurrentIndex(newIndex);
    };

    const handleTouchStart = (e: React.TouchEvent) => {
        setTouchStart(e.targetTouches[0].clientX);
    };

    const handleTouchEnd = (e: React.TouchEvent) => {
        if (touchStart === null) return;
        const touchEnd = e.changedTouches[0].clientX;
        const distance = touchStart - touchEnd;
        const swipeThreshold = 50;

        if (distance > swipeThreshold) { // Swiped left
            goToNext();
        } else if (distance < -swipeThreshold) { // Swiped right
            goToPrevious();
        }
        setTouchStart(null);
    };

    return (
        <div 
          className="fixed inset-0 bg-black bg-opacity-90 z-[60] flex flex-col items-center justify-center animate-fade-in" 
          onClick={onClose}
          onTouchStart={handleTouchStart}
          onTouchEnd={handleTouchEnd}
          role="dialog"
          aria-modal="true"
        >
            <div className="absolute top-0 left-0 right-0 h-16 flex items-center justify-end px-4">
                <button onClick={onClose} className="text-white p-2" aria-label="إغلاق المعرض">
                    <XMarkIcon className="w-7 h-7" />
                </button>
            </div>

            <div className="relative w-full h-full flex items-center justify-center">
                 <img src={images[currentIndex]} alt={`${productName} - صورة ${currentIndex + 1}`} className="max-h-[80%] max-w-[90%] object-contain" />
            </div>

            <div className="absolute bottom-4 text-white text-lg font-mono">
                {currentIndex + 1} / {images.length}
            </div>
             <style>{`
                @keyframes fade-in {
                    from { opacity: 0; }
                    to { opacity: 1; }
                }
                .animate-fade-in { animation: fade-in 0.2s ease-out forwards; }
            `}</style>
        </div>
    );
};


interface ProductDetailsPageProps {
  product: Product;
  onAddToCart: (product: Product, size: string) => void;
  addNotification: (message: string) => void;
  isSaved: boolean;
  onSaveToggle: (productId: string) => void;
}

const ProductDetailsPage: React.FC<ProductDetailsPageProps> = ({ product, onAddToCart, addNotification, isSaved, onSaveToggle }) => {
  const [quantity, setQuantity] = useState(1);
  const [currentMainImageIndex, setCurrentMainImageIndex] = useState(0);
  const [isGalleryOpen, setIsGalleryOpen] = useState(false);

  // Swipe State
  const [touchStart, setTouchStart] = useState<number | null>(null);
  const [touchEnd, setTouchEnd] = useState<number | null>(null);

  const handleAddToCartClick = () => {
    const sizeName = `سيرية (${product.series_count} قطع)`;
    for (let i = 0; i < quantity; i++) {
        onAddToCart(product, sizeName);
    }
  };

  const handleQuantityChange = (delta: number) => {
      const newQty = quantity + delta;

      let maxStock = product.stock;

      if (newQty >= 1 && newQty <= maxStock) {
          setQuantity(newQty);
      }
  };

  const handleCopyText = (text: string) => {
      if (!text) return;
      navigator.clipboard.writeText(text);
      addNotification('تم نسخ النص');
  };

  // Swipe Handlers
  const onTouchStart = (e: React.TouchEvent) => {
      setTouchEnd(null);
      setTouchStart(e.targetTouches[0].clientX);
  }

  const onTouchMove = (e: React.TouchEvent) => {
      setTouchEnd(e.targetTouches[0].clientX);
  }

  const onTouchEnd = () => {
      if (!touchStart || !touchEnd) return;
      const distance = touchStart - touchEnd;
      const isLeftSwipe = distance > 50;
      const isRightSwipe = distance < -50;

      if (isLeftSwipe) {
           setCurrentMainImageIndex((prev) => (prev === product.image_urls.length - 1 ? 0 : prev + 1));
      }
      if (isRightSwipe) {
          setCurrentMainImageIndex((prev) => (prev === 0 ? product.image_urls.length - 1 : prev - 1));
      }
  }

  // Determine content for Promo Tab
  const marketingText = product.marketing_description || product.promo || 'لا يوجد نص ترويجي محدد.';

  // Determine display price
  const displayPrice = product.price;

  return (
    <div className="bg-white dark:bg-slate-900 min-h-screen pb-32 font-cairo relative">
       {isGalleryOpen && (
            <ImageGalleryModal
                images={product.image_urls}
                initialIndex={currentMainImageIndex}
                onClose={() => setIsGalleryOpen(false)}
                productName={product.name}
            />
        )}

      {/* 1. Curved Image Header with Swipe - Square Aspect Ratio */}
      <div 
        className="relative w-full aspect-square bg-gray-100 dark:bg-gray-800 rounded-b-[30px] overflow-hidden shadow-sm z-0 touch-pan-y"
        onTouchStart={onTouchStart}
        onTouchMove={onTouchMove}
        onTouchEnd={onTouchEnd}
      >
          <img 
            src={product.image_urls[currentMainImageIndex]} 
            alt={product.name} 
            className="w-full h-full object-cover transition-opacity duration-300"
            onClick={() => setIsGalleryOpen(true)}
          />

          {/* Pagination Dots */}
          <div className="absolute bottom-4 left-1/2 -translate-x-1/2 flex gap-1.5">
              {product.image_urls.map((_, idx) => (
                  <button 
                    key={idx}
                    onClick={(e) => { e.stopPropagation(); setCurrentMainImageIndex(idx); }}
                    className={`w-1.5 h-1.5 rounded-full transition-all duration-300 ${currentMainImageIndex === idx ? 'bg-yellow-400 w-3' : 'bg-white/80 hover:bg-white'}`}
                  />
              ))}
          </div>
      </div>

      <div className="px-4 pt-6">
          {/* 2. Product Name Heading (Title is in Header, but we keep it clean here as a heading) */}
          <div className="text-right mb-4">
              <h1 className="text-xl font-black text-gray-900 dark:text-white leading-tight">{product.name}</h1>
          </div>

          {/* Wholesale Price & Stock */}
          <div className="flex items-center justify-between mb-4">
              <div className="flex flex-col">
                  <span className="text-xs text-gray-500 dark:text-gray-400 font-bold mb-1">
                      سعر السيرية
                  </span>
                  <p className="text-2xl font-black text-primary dark:text-primary-light leading-none">
                      {displayPrice.toLocaleString()} <span className="text-xs font-bold text-gray-500 dark:text-gray-400">د.ع</span>
                  </p>
              </div>

              <div className="flex flex-col items-end">
                  <span className="text-xs text-gray-500 dark:text-gray-400 font-bold mb-1">المخزون</span>
                  <p className="text-base font-black text-gray-800 dark:text-gray-200 leading-none dir-ltr">
                      {product.stock} سيرية
                  </p>
              </div>
          </div>

          {/* Divider */}
          <div className="border-b border-gray-100 dark:border-gray-800 mb-4"></div>

          {/* 3. Primary Color Price Range Bar (Curved Soft Rectangle - Telegram Style) */}
          <div className="w-full bg-primary-light dark:bg-primary/10 text-primary dark:text-primary-light py-3.5 px-4 rounded-2xl border border-primary/20 flex justify-between items-center mb-6 shadow-sm">
              <span className="text-xs font-black flex items-center gap-2">
                  <i className="fa-solid fa-tags"></i>
                  سعر الزبون المقترح
                  <span className="text-[10px] opacity-70 font-bold">(للسيرية)</span>
              </span>
              <span className="font-black dir-ltr text-sm">
                  {product.min_sell_price.toLocaleString()} - {product.max_sell_price.toLocaleString()} <span className="text-[10px]">د.ع</span>
              </span>
          </div>

          {/* 4. Streamlined Size & Quantity Row - Clean Style */}
          <div id="size-selection-section" className="mb-6">
              <div className="bg-blue-50 dark:bg-blue-900/10 border border-blue-100 dark:border-blue-900/30 p-4 rounded-2xl mb-4 text-center">
                  <p className="text-sm font-black text-blue-800 dark:text-blue-300">محتويات السيرية</p>
                  <p className="text-xs text-blue-600 dark:text-blue-400 mt-1.5 font-bold">{product.series_sizes}</p>
                  <p className="text-[10px] text-blue-400 dark:text-blue-500 mt-2 font-bold">إجمالي عدد القطع: {product.series_count}</p>
              </div>

              {/* Quantity Selector (Compact - Clean Style) */}
              <div className="flex justify-between items-center bg-gray-50 dark:bg-gray-800/50 p-4 rounded-2xl border border-gray-100 dark:border-gray-700">
                  <span className="font-black text-gray-700 dark:text-gray-300 text-sm">
                      الكمية (بالسيرية)
                  </span>

                  <div className="flex items-center gap-4 h-full">
                       <button 
                          onClick={() => handleQuantityChange(1)}
                          className="w-10 h-10 rounded-xl bg-white dark:bg-gray-700 text-primary shadow-sm flex items-center justify-center active:scale-95 transition-all border border-gray-100 dark:border-gray-600 hover:border-primary/30"
                      >
                          <PlusIcon className="w-5 h-5" />
                      </button>
                      <span className="font-black text-xl text-gray-800 dark:text-white w-8 text-center">{quantity}</span>
                      <button 
                          onClick={() => handleQuantityChange(-1)}
                          className="w-10 h-10 rounded-xl bg-white dark:bg-gray-700 text-gray-500 shadow-sm flex items-center justify-center active:scale-95 transition-all border border-gray-100 dark:border-gray-600 hover:bg-gray-50"
                      >
                          <MinusIcon className="w-5 h-5" />
                      </button>
                  </div>
              </div>
          </div>

          {/* Straight Line Separator */}
          <div className="border-t border-gray-200 dark:border-gray-700 mb-6"></div>

          {/* 5. Content (Promo Only) */}
          <div>
              {/* Telegram Link Button - Soft Rectangle */}
              {product.telegramUrl && (
                  <div className="mb-6 w-full">
                      <a 
                          href={product.telegramUrl} 
                          target="_blank" 
                          rel="noopener noreferrer"
                          className="w-full flex items-center justify-center gap-3 bg-[#229ED9]/10 text-[#229ED9] hover:bg-[#229ED9] hover:text-white py-3 rounded-2xl transition-all duration-300 text-sm font-black border border-[#229ED9]/20 shadow-sm"
                      >
                          <i className="fa-brands fa-telegram text-xl"></i>
                          <span>حمل صور او فيديو المنتج من تليكرام</span>
                      </a>
                  </div>
              )}

              {/* Promo Content Header */}
              <div className="flex items-center gap-2 mb-4">
                  <h3 className="font-black text-gray-800 dark:text-gray-200 text-sm">وصف ترويجي للنشر</h3>
                  <span className="text-[10px] text-gray-400 dark:text-gray-500 font-bold">(جاهز للنسخ)</span>
              </div>

              <div className="text-right leading-relaxed min-h-[100px] animate-fade-in pb-8">
                  {/* Promo Content */}
                  <div className="relative block bg-gray-50 dark:bg-gray-800/50 p-5 rounded-2xl border border-gray-100 dark:border-gray-700">
                      <button 
                        onClick={() => handleCopyText(marketingText)}
                        className="float-left ml-0 mr-3 mb-3 flex items-center gap-2 bg-white dark:bg-gray-700 hover:bg-gray-100 dark:hover:bg-gray-600 text-primary dark:text-primary-light border border-gray-200 dark:border-gray-600 rounded-xl px-4 py-2 transition-all shadow-sm active:scale-95 text-xs font-black"
                        aria-label="نسخ الوصف الترويجي"
                      >
                          <CopyIcon className="w-4 h-4" />
                          <span>نسخ النص</span>
                      </button>
                      <div className="text-right text-gray-800 dark:text-gray-200 text-base font-bold leading-loose whitespace-pre-wrap">
                          {marketingText}
                      </div>
                  </div>
              </div>
          </div>
      </div>

      {/* 6. Fixed Bottom Button - Small & Compact - Soft Rectangle */}
      <div className="fixed bottom-0 left-0 right-0 w-full bg-white/80 dark:bg-gray-900/80 backdrop-blur-md px-4 py-4 shadow-[0_-4px_30px_rgba(0,0,0,0.08)] z-10 border-t border-gray-100 dark:border-gray-800">
          <button 
            onClick={handleAddToCartClick}
            disabled={(product.stock === 0)}
            className="w-full bg-primary text-white hover:bg-primary/90 active:scale-95 transition-all duration-300 font-black text-base py-3.5 rounded-2xl shadow-lg shadow-primary/25 disabled:bg-gray-300 disabled:text-gray-500 disabled:cursor-not-allowed flex items-center justify-center gap-3"
          >
              <CartIcon className="w-5 h-5" />
              <span>
                  {product.stock === 0 ? 'نفذت الكمية تماماً' : 'أضف السيرية إلى السلة الآن'}
              </span>
          </button>
      </div>
    </div>
  );
};

export default ProductDetailsPage;

